from typing import NamedTuple

import procfunc as pf
from procfunc.nodes import types as t

from infinigen_v2.generators.shaders.functionality_lists import (
    furniture_material_distribution,
)


class SlotCabinetResult(NamedTuple):
    mesh: pf.MeshObject


@pf.nodes.node_function
def box(
    dimensions: t.SocketOrVal[pf.Vector] = (0.39, 0.335, 0.02),
    origin: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    vertices_x: t.SocketOrVal[int] = 2,
    vertices_y: t.SocketOrVal[int] = 2,
    vertices_z: t.SocketOrVal[int] = 2,
) -> pf.ProcNode:
    # Code generated by procfunc v0.30.2
    cube = pf.nodes.geo.mesh_cube(
        vertices_x=vertices_x,
        vertices_y=vertices_y,
        vertices_z=vertices_z,
    )

    input_position = pf.nodes.geo.input_position()

    set_position_position = pf.nodes.math.map_range(
        value=input_position,
        from_max=(0.5, 0.5, 0.5),
        from_min=(-0.5, -0.5, -0.5),
        to_max=origin + dimensions,
        to_min=origin,
    )

    set_position = pf.nodes.geo.set_position(
        geometry=cube.mesh, position=set_position_position
    )

    return set_position


def metric_box_uv(geometry: pf.ProcNode) -> pf.ProcNode:
    """Store metric box-projection UVs computed from the current positions.

    Per face, picks the two in-plane position axes so texture directions stay
    aligned with the board edges, rotated 90deg so grain runs along the
    boards, then writes them as a CORNER "UVMap".
    """
    position = pf.nodes.geo.input_position()
    abs_normal = pf.nodes.math.vector_absolute(pf.nodes.geo.input_normal())
    uv_facing_x = pf.nodes.math.combine_xyz(x=position.y, y=position.z)
    uv_facing_y = pf.nodes.math.combine_xyz(x=position.x, y=position.z)
    uv_facing_z = pf.nodes.math.combine_xyz(x=position.x, y=position.y)
    uv_side = pf.nodes.func.switch(
        switch=abs_normal.y > 0.5, a=uv_facing_x, b=uv_facing_y
    )
    uv = pf.nodes.func.switch(switch=abs_normal.z > 0.5, a=uv_side, b=uv_facing_z)
    uv = pf.nodes.math.combine_xyz(x=uv.y * -1.0, y=uv.x)
    return pf.nodes.geo.store_named_attribute(
        geometry=geometry,
        name="UVMap",
        value=uv,
        domain="CORNER",
        data_type="FLOAT2",
    )


@pf.nodes.node_function
def box_even(
    dimensions: t.SocketOrVal[pf.Vector] = (0.39, 0.335, 0.02),
    origin: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    face_size_approx: t.SocketOrVal[pf.Vector] = (1.0, 1.0, 1.0),
) -> pf.ProcNode:
    # Code generated by procfunc v0.30.2
    box_vertices_x_a = pf.nodes.math.vector_ceil(dimensions / face_size_approx)

    box_vertices_x = box_vertices_x_a + (1.0, 1.0, 1.0)
    box_result = box(
        dimensions=dimensions,
        origin=origin,
        vertices_x=box_vertices_x.x.astype(dtype=int),
        vertices_y=box_vertices_x.y.astype(dtype=int),
        vertices_z=box_vertices_x.z.astype(dtype=int),
    )
    return box_result


class GridWithIndicesResult(NamedTuple):
    mesh: pf.ProcNode[pf.MeshObject]
    index_x: pf.ProcNode[int]
    index_y: pf.ProcNode[int]


@pf.nodes.node_function
def grid_with_indices(
    vertices_x: t.SocketOrVal[int] = 10,
    vertices_y: t.SocketOrVal[int] = 10,
) -> GridWithIndicesResult:
    # Code generated by procfunc v0.30.2
    curve_line = pf.nodes.geo.curve_line(end=(1.0, 0.0, 0.0), start=(0, 0, 0))

    resample_curve_count = pf.nodes.geo.resample_curve_count(
        curve=curve_line, count=vertices_x
    )

    spline_parameter = pf.nodes.geo.spline_parameter()

    capture_attribute = pf.nodes.geo.capture_attribute(
        geometry=resample_curve_count,
        factor=spline_parameter.factor,
    )

    input_index = pf.nodes.geo.input_index()

    capture_attribute_1 = pf.nodes.geo.capture_attribute(
        geometry=capture_attribute.geometry,
        index=input_index,
    )

    curve_line_1 = pf.nodes.geo.curve_line(end=(-1.0, 0.0, 0.0), start=(0, 0, 0))

    resample_curve_count_1 = pf.nodes.geo.resample_curve_count(
        curve=curve_line_1, count=vertices_y
    )

    capture_attribute_2 = pf.nodes.geo.capture_attribute(
        geometry=resample_curve_count_1,
        factor=spline_parameter.factor,
    )

    input_index_1 = pf.nodes.geo.input_index()

    capture_attribute_3 = pf.nodes.geo.capture_attribute(
        geometry=capture_attribute_2.geometry,
        index=input_index_1,
    )

    curve_to = pf.nodes.geo.curve_to_mesh(
        curve=capture_attribute_1.geometry,
        profile_curve=capture_attribute_3.geometry,
    )

    return GridWithIndicesResult(
        curve_to,
        capture_attribute_1.index,
        capture_attribute_3.index,
    )


@pf.nodes.node_function
def shelf(
    dimensions: t.SocketOrVal[pf.Vector] = (1.0, 1.0, 1.0),
    n_spaces_y: t.SocketOrVal[int] = 0,
    n_spaces_z: t.SocketOrVal[int] = 0,
    frame_board_dimensions: t.SocketOrVal[pf.Vector] = (0.0, 0.0, 0.0),
    row_divider_width: t.SocketOrVal[float] = 0.0,
    col_divider_width: t.SocketOrVal[float] = 0.0,
    back_width: t.SocketOrVal[float] = 0.05,
) -> pf.ProcNode:
    # Code generated by procfunc v0.30.2
    top_bottom_board_dim = pf.nodes.math.combine_xyz(
        x=dimensions.x, y=dimensions.y, z=frame_board_dimensions.z
    )

    top_board_dimensions = pf.nodes.math.vector_multiply_add(
        a=frame_board_dimensions,
        b=(0.0, -2.0, 0.0),
        addend=top_bottom_board_dim,
    )
    bottom_board_origin = frame_board_dimensions * (0.0, 1.0, 0.0)

    top_board_vertices_y = n_spaces_y.astype(dtype=float) + 1.0

    bottom_board = box(
        dimensions=top_board_dimensions,
        origin=bottom_board_origin,
        vertices_y=top_board_vertices_y.astype(dtype=int),
    )

    # interior clearance above each cell's support surface
    cell_interior_z = pf.nodes.math.multiply_add(
        a=frame_board_dimensions.z, b=-1.0, addend=dimensions.z
    ) / n_spaces_z.astype(dtype=float)
    cell_clearance = cell_interior_z - row_divider_width

    dim_sub_1frame = dimensions - frame_board_dimensions

    top_board_origin = pf.nodes.math.vector_multiply_add(
        a=dim_sub_1frame,
        b=(0.0, 0.0, 1.0),
        addend=bottom_board_origin,
    )

    top_board = box(
        dimensions=top_board_dimensions,
        origin=top_board_origin,
        vertices_y=top_board_vertices_y.astype(dtype=int),
    )
    edge_board_dim_no_margin = pf.nodes.math.combine_xyz(
        x=dimensions.x, y=frame_board_dimensions.y, z=dimensions.z
    )

    right_board = box_even(
        dimensions=edge_board_dim_no_margin,
        origin=dim_sub_1frame * (0.0, 1.0, 0.0),
        face_size_approx=(0.7, 0.7, 0.7),
    )

    left_board = box_even(
        dimensions=edge_board_dim_no_margin, face_size_approx=(0.7, 0.7, 0.7)
    )

    join_sides = pf.nodes.geo.join_geometry(
        [bottom_board, top_board, right_board, left_board]
    )

    enable_back_switch = pf.nodes.func.equal(a=back_width, b=0.0, epsilon=0.001)

    dim_sub_2frame = pf.nodes.math.vector_multiply_add(
        a=frame_board_dimensions,
        b=(-2.0, -2.0, -2.0),
        addend=dimensions,
    )

    box_dimensions = pf.nodes.math.vector_multiply_add(
        a=back_width.astype(dtype=pf.Vector),
        b=(1.0, 0.0, 0.0),
        addend=dim_sub_2frame * (0.0, 1.0, 1.0),
    )

    box_result = box(
        dimensions=box_dimensions, origin=frame_board_dimensions * (0.0, 1.0, 1.0)
    )
    enable_back = pf.nodes.func.switch(switch=enable_back_switch, a=box_result)

    grid_1 = n_spaces_y.astype(dtype=float) + 1.0

    grid_0 = n_spaces_z.astype(dtype=float) + 1.0
    grid_with_indices_result = grid_with_indices(
        vertices_x=grid_1.astype(dtype=int),
        vertices_y=grid_0.astype(dtype=int),
    )
    transform = pf.nodes.geo.transform(
        geometry=grid_with_indices_result.mesh,
        rotation=(1.570796, 0.0, 1.570796),
    )

    input_position = pf.nodes.geo.input_position()

    offset_forward_avoid_backplate = pf.nodes.math.vector_scale(
        vector=(1.0, 0.0, 0.0), scale=back_width
    )

    bottomleft_interior_point = frame_board_dimensions * (0.0, 1.0, 1.0)

    set_position_position_to_min = pf.nodes.math.vector_multiply_add(
        a=row_divider_width.astype(dtype=pf.Vector),
        b=(0.0, 0.0, -0.5),
        addend=offset_forward_avoid_backplate + bottomleft_interior_point,
    )

    topright_interior_point = pf.nodes.math.vector_multiply_add(
        a=frame_board_dimensions,
        b=(0.0, -1.0, -1.0),
        addend=dimensions,
    )

    set_position_position_to_max = pf.nodes.math.vector_multiply_add(
        a=row_divider_width.astype(dtype=pf.Vector),
        b=(0.0, 0.0, 0.5),
        addend=topright_interior_point + offset_forward_avoid_backplate,
    )

    set_position_position = pf.nodes.math.map_range(
        value=input_position,
        from_max=(1.0, 1.0, 1.0),
        from_min=(0.0, 0.0, 0.0),
        to_max=set_position_position_to_max,
        to_min=set_position_position_to_min,
    )
    set_position = pf.nodes.geo.set_position(
        geometry=transform, position=set_position_position
    )
    is_left = pf.nodes.func.equal(a=grid_with_indices_result.index_x, b=0)

    is_bottom = pf.nodes.func.equal(a=grid_with_indices_result.index_y, b=0)
    is_top = pf.nodes.func.equal(a=grid_with_indices_result.index_y, b=n_spaces_z)
    instance_b_a = pf.nodes.func.boolean_or(a=is_bottom, b=is_top)

    instance_b_1 = pf.nodes.func.boolean_not(instance_b_a)
    instance_horizontal_boards_selection = pf.nodes.func.boolean_and(
        a=is_left, b=instance_b_1
    )
    vert_board_dimensions_x = dimensions.x - back_width

    hor_board_dims_y = pf.nodes.math.multiply_add(
        a=frame_board_dimensions.y, b=-2.0, addend=dimensions.y
    )

    hor_board_dims = pf.nodes.math.combine_xyz(
        x=vert_board_dimensions_x,
        y=hor_board_dims_y,
        z=row_divider_width,
    )
    box_1 = n_spaces_y.astype(dtype=float) + 1.0

    box_result_1 = box(
        dimensions=hor_board_dims,
        origin=row_divider_width.astype(dtype=pf.Vector) * (0.0, 0.0, -0.5),
        vertices_y=box_1.astype(dtype=int),
    )
    instance_horizontal_boards = pf.nodes.geo.instance_on_points(
        points=set_position,
        instance=box_result_1,
        selection=instance_horizontal_boards_selection,
    )

    is_right = pf.nodes.func.equal(a=grid_with_indices_result.index_x, b=n_spaces_y)

    instance_a_a = pf.nodes.func.boolean_or(a=is_left, b=is_right)

    instance_a = pf.nodes.func.boolean_not(instance_a_a)
    instance_b_0 = pf.nodes.func.boolean_not(is_top)
    instance_vertical_boards_selection = pf.nodes.func.boolean_and(
        a=instance_a, b=instance_b_0
    )
    vert_board_dimensions = pf.nodes.math.combine_xyz(
        x=vert_board_dimensions_x,
        y=col_divider_width,
        z=cell_clearance,
    )
    vert_board_origin = pf.nodes.math.vector_multiply_add(
        a=col_divider_width.astype(dtype=pf.Vector),
        b=(0.0, -0.5, 0.0),
        addend=row_divider_width.astype(dtype=pf.Vector) * (0.0, 0.0, 0.5),
    )
    vert_board = box_even(dimensions=vert_board_dimensions, origin=vert_board_origin)
    instance_vertical_boards = pf.nodes.geo.instance_on_points(
        points=set_position,
        instance=vert_board,
        selection=instance_vertical_boards_selection,
    )

    join = pf.nodes.geo.join_geometry(
        [join_sides, enable_back, instance_horizontal_boards, instance_vertical_boards]
    )

    realize_instances = pf.nodes.geo.realize_instances(join)

    return realize_instances


def slot_cabinet_distribution(
    rng: pf.RNG,
    dimensions: pf.Vector | None = None,
    frame_material: pf.Material | None = None,
    back_width: float | None = None,
) -> SlotCabinetResult:
    if dimensions is None:
        depth = pf.random.uniform(rng, 0.25, 0.45)
        width = pf.random.uniform(rng, 0.7, 2.5)
        height = pf.random.uniform(rng, 0.8, 2.2)
        dimensions = pf.Vector((depth, width, height))

    # sample goal cell dims, then fit cell counts to best match overall dimensions;
    # goal width ranges up to the full width so a single full-width row stays an option
    goal_cell_width = pf.random.uniform(rng, 0.3, max(0.6, dimensions.y))
    goal_cell_height = pf.random.uniform(rng, 0.375, 0.45)
    n_spaces_y = max(1, round(dimensions.y / goal_cell_width))
    n_spaces_z = max(1, round(dimensions.z / goal_cell_height))

    frame_thickness = pf.random.uniform(rng, 0.02, 0.06)
    row_divider_width = pf.random.uniform(rng, 0.015, 0.05)
    col_divider_width = pf.random.uniform(rng, 0.01, 0.04)
    if back_width is None:
        rng_choice, rng_back = rng.spawn(2)
        back_width = pf.control.choice(
            rng_choice,
            [
                (0.0, 0.25),
                (pf.random.uniform(rng_back, 0.01, 0.04), 0.75),
            ],
        )

    vec = pf.nodes.shader.coord().uv
    if frame_material is None:
        (rng_mat,) = rng.spawn(1)
        frame_material = furniture_material_distribution(rng_mat, vec)

    geo = shelf(
        dimensions=dimensions,
        n_spaces_y=n_spaces_y,
        n_spaces_z=n_spaces_z,
        frame_board_dimensions=(frame_thickness, frame_thickness, frame_thickness),
        row_divider_width=row_divider_width,
        col_divider_width=col_divider_width,
        back_width=back_width,
    )
    geo = metric_box_uv(geo)
    geo = pf.nodes.geo.set_material(geometry=geo, material=frame_material)

    result = pf.nodes.to_mesh_object(geo)
    return SlotCabinetResult(mesh=result)
